    my @dist = (-1) x ($N + 1);            # 距離配列（-1 は未訪問）
    $dist[$start] = 0;                      # スタート地点は 0
    my @q = ($start);                       # BFS キュー
    my ($farthest, $max_dist) = ($start, 0);

